section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/junior-ai-co-pilot-curriculum",
  "type": "object",
  "required": ["junior_name", "mentor_name", "weeks", "modules", "rubric", "tool"],
  "properties": {
    "junior_name": {"type": "string", "minLength": 1},
    "mentor_name": {"type": "string", "minLength": 1},
    "tool": {"type": "string", "description": "Primary AI co-pilot, e.g. Claude Code"},
    "weeks": {"type": "integer", "minimum": 4, "maximum": 8},
    "modules": {
      "type": "array",
      "minItems": 6,
      "items": {
        "type": "object",
        "required": ["id", "title", "week", "exercise", "reflection_required"],
        "properties": {
          "id": {"type": "string"},
          "title": {"type": "string"},
          "week": {"type": "integer", "minimum": 1, "maximum": 8},
          "exercise": {"type": "string"},
          "reflection_required": {"type": "boolean", "const": true}
        }
      }
    },
    "rubric": {
      "type": "array",
      "minItems": 10,
      "items": {
        "type": "object",
        "required": ["id", "statement", "evidence"],
        "properties": {
          "id": {"type": "string"},
          "statement": {"type": "string"},
          "evidence": {"type": "string"}
        }
      }
    },
    "mentor_schedule": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["week", "duration_minutes", "agenda"],
        "properties": {
          "week": {"type": "integer"},
          "duration_minutes": {"type": "integer", "minimum": 30},
          "agenda": {"type": "string"}
        }
      }
    }
  }
}

example.code:
{
  "junior_name": "Alex Doe",
  "mentor_name": "Sam Mentor",
  "tool": "Claude Code",
  "weeks": 6,
  "modules": [
    {"id": "m1", "title": "Prompt anatomy", "week": 1, "exercise": "Refactor 3 prompts using XML structure", "reflection_required": true},
    {"id": "m2", "title": "Hallucination check", "week": 2, "exercise": "Find and document 5 hallucinations in AI output", "reflection_required": true},
    {"id": "m3", "title": "Scoped edits", "week": 3, "exercise": "Make 5 changes < 50 LOC each with diff review", "reflection_required": true},
    {"id": "m4", "title": "Test-first AI", "week": 4, "exercise": "Write tests before AI generates implementation", "reflection_required": true},
    {"id": "m5", "title": "Security boundaries", "week": 5, "exercise": "Run IPI eval suite, document 3 findings", "reflection_required": true},
    {"id": "m6", "title": "Mentor review", "week": 6, "exercise": "Co-pilot PR walkthrough with mentor", "reflection_required": true}
  ],
  "rubric": [
    {"id": "r1", "statement": "Can spot a fabricated API in generated code", "evidence": "Exercise m2 reflection"},
    {"id": "r2", "statement": "Writes prompts with explicit input/output contract", "evidence": "PR samples"}
  ]
}
